fn f4se_worker_payload_round_trips_owned_scan_snapshot() {
    let task = WorkerTask::new("s06-f4se-scan:7", WorkerTaskKind::Scan);
    let snapshot = F4seScanSnapshot::ready(Vec::new());
    let event = WorkerEvent::completed(
