        settings.overview_issues = false;
        settings.errors = false;
        settings.wrong_format = false;
        settings.loose_previs = false;
        settings.junk_files = false;
        settings.problem_overrides = false;
        settings.race_subgraphs = false;
        let mut controller = ScannerController::new(settings);

        assert!(!controller.scan_button_enabled());
        assert_eq!(controller.status_text(), SCANNER_NO_ENABLED_CATEGORIES_MESSAGE);
        assert!(controller.request_scan().is_none());
        assert_eq!(controller.next_scan_id(), 1);
